import React, { useState } from 'react';

export default function StarRating({ maxStars = 5, initialRating = 0, onChange }) {
  const [rating, setRating] = useState(initialRating);
  const [hoverRating, setHoverRating] = useState(null);

  const handleRating = (val) => {
    setRating(val);
    if (onChange) onChange(val);
  };

  return (
    <div className="flex gap-1 select-none items-center">
      {Array.from({ length: maxStars }).map((_, idx) => {
        const starValue = idx + 1;
        const isHighlighted = hoverRating !== null ? starValue <= hoverRating : starValue <= rating;

        return (
          <button
            key={idx}
            type="button"
            onClick={() => handleRating(starValue)}
            onMouseEnter={() => setHoverRating(starValue)}
            onMouseLeave={() => setHoverRating(null)}
            className="focus:outline-none transition-transform active:scale-95"
          >
            <svg
              className={`w-8 h-8 transition-colors duration-150 ${
                isHighlighted ? 'text-amber-400 fill-amber-400' : 'text-gray-300 fill-transparent'
              }`}
              viewBox="0 0 24 24"
              stroke="currentColor"
              strokeWidth={2}
            >
              <path
                strokeLinecap="round"
                strokeLinejoin="round"
                d="M11.049 2.927c.3-.921 1.603-.921 1.902 0l1.519 4.674a1 1 0 00.95.69h4.907c.961 0 1.36 1.242.58 1.8l-3.97 2.88a1 1 0 00-.364 1.118l1.518 4.674c.3.922-.755 1.688-1.538 1.118l-3.971-2.88a1 1 0 00-1.176 0l-3.97 2.88c-.783.57-1.838-.197-1.538-1.118l1.518-4.674a1 1 0 00-.364-1.118l-3.97-2.88c-.78-.558-.38-1.81.58-1.8h4.908a1 1 0 00.95-.69l1.519-4.674z"
              />
            </svg>
          </button>
        );
      })}
      {rating > 0 && (
        <span className="text-gray-500 font-bold ml-2 text-sm">({rating} / {maxStars})</span>
      )}
    </div>
  );
}
